bi_anomalias_negociacao.php:62:$rowsStmt = $conn->prepare("\n    SELECT\n        hospital_id,\n        hospital,\n        COUNT(DISTINCT id_internacao) AS internacoes,\n        COUNT(id_negociacao) AS negociacoes,\n        SUM(saving_calc) AS saving_total\n    FROM (\n        SELECT\n            i.id_internacao,\n            h.id_hospital AS hospital_id,\n            h.nome_hosp AS hospital,\n            ng.id_negociacao,\n            MAX({$savingExpr}) AS saving_calc\n        FROM tb_internacao i\n        LEFT JOIN tb_negociacao ng ON ng.fk_id_int = i.id_internacao\n        LEFT JOIN tb_acomodacao aco_de ON aco_de.fk_hospital = i.fk_hospital_int\n            AND LOWER(TRIM(aco_de.acomodacao_aco)) = LOWER(TRIM(IF(LOCATE('-', ng.troca_de) > 0, SUBSTRING_INDEX(ng.troca_de, '-', -1), ng.troca_de)))\n        LEFT JOIN tb_acomodacao aco_para ON aco_para.fk_hospital = i.fk_hospital_int\n            AND LOWER(TRIM(aco_para.acomodacao_aco)) = LOWER(TRIM(IF(LOCATE('-', ng.troca_para) > 0, SUBSTRING_INDEX(ng.troca_para, '-', -1), ng.troca_para)))\n        {$internJoins}\n        WHERE {$internWhere}\n        GROUP BY i.id_internacao, h.id_hospital, h.nome_hosp, ng.id_negociacao\n    ) neg\n    WHERE hospital_id IS NOT NULL\n    GROUP BY hospital_id, hospital\n    ORDER BY negociacoes DESC, saving_total DESC\n    LIMIT 10\n");
